INSERT INTO tools (
  name, slug, tagline, description, website_url,
  pricing_type, pricing_details, skill_level, has_api, platforms,
  features, integrations, is_published,
  best_for, not_for, editorial_verdict,
  last_verified_at
) VALUES

-- ── trainual → productivity ─────────────────────────────────
('Trainual', 'trainual', 'AI onboarding, training, and SOP platform — turn processes into role-based training and an always-on AI assistant.', 'Trainual is an AI-powered training, onboarding, and SOP-documentation platform that turns company processes into structured training paths and a queryable AI knowledge assistant. The product covers content authoring (AI generates training from policies and SOPs in minutes), role-based delivery (paths customized by role / team / location), real-time collaboration (editing, comments, approvals), AI Q&A (ask the company knowledge base anything), reporting (completion + comprehension), org-chart documentation, and software-inventory tracking with ownership. E-signatures and audit-ready acknowledgments handle compliance for regulated workflows. Trainual positions against the Loom + Notion combo (fragmented, not AI-native), Lessonly and Docebo (LMS-heavy, slower setup), and Process Street / SweetProcess (workflow-checklist-first, no AI-assistant layer). The differentiator is the unified AI knowledge layer plus org-hierarchy documentation in one platform.', 'https://trainual.com', 'paid', '[]'::jsonb, 'beginner', false, '{"web","mobile","plugin"}', '{"AI generates training content from SOPs and policies","Role-based training paths by role / team / location","Real-time collaboration — editing, comments, approvals","Trainual AI assistant for instant org Q&A","Detailed reporting on completion and comprehension","Org chart and roles-to-responsibilities mapping","Software / tools inventory with ownership tracking","E-signatures and audit-ready acknowledgments","AI-built assessments and quizzes","Chrome extension + iOS + Android apps"}', '{"Slack","Microsoft Teams","BambooHR","Gusto","Rippling","Zapier"}', true, '{"SMB and mid-market companies onboarding new hires at velocity","Operations-led teams documenting SOPs and processes for the first time","Multi-location franchises needing role-based training distribution","Compliance-bound industries requiring audit-trail acknowledgments"}', '{"Pure LMS workloads with SCORM / xAPI compliance (Docebo / Cornerstone fit better)","Single-doc workflow checklists (Process Street is cheaper for that scope)","Companies already deep in Notion or Confluence as the source of truth","Free-tier seekers — Trainual is paid-only, no genuine free plan"}', 'The default SOP-and-onboarding platform for SMB and mid-market companies that have outgrown the Loom-plus-Notion stack and want one tool with role-based training, AI Q&A, and org-chart documentation in a single bill. Trainual''s AI assistant layer over your own SOPs is genuinely useful — new hires ask questions instead of pinging Slack. It''s weaker than Docebo on enterprise LMS depth, weaker than Process Street on lightweight checklist workflows, and the no-public-tier-pricing posture is friction. Pick Trainual when you''re scaling past 25 employees and onboarding is a real bottleneck.', now()),

-- ── brand24 → marketing-seo ─────────────────────────────────
('Brand24', 'brand24', 'AI social listening — track brand mentions across 25M+ sources, sentiment analysis, hashtag tracking, and competitive intelligence.', 'Brand24 is an AI-powered media-monitoring and social-listening platform tracking brand mentions, sentiment, and competitive signal across 25+ million online sources — social media, news, blogs, videos, podcasts, forums, and review sites. Real-time monitoring fires alerts on every mention; sentiment analysis segments positive / negative / neutral with AI-trained classifiers; hashtag tracking measures reach and identifies influencers; multi-language support spans 108 languages with auto-detection; reputation scoring distills mention volume into trend lines and word clouds; automated reports compile PR coverage metrics for stakeholder distribution. Brand24 positions against Mention (similar SMB-focused tool), Talkwalker and Meltwater (enterprise-incumbent, materially more expensive), Sprinklr (suite play with broader marketing-cloud scope), Brandwatch (research-heavy, agency-favored), and Notify (alerts-only specialist). The differentiator is the SMB-friendly price point with enterprise-grade source coverage.', 'https://brand24.com', 'paid', '[]'::jsonb, 'beginner', true, '{"web","api"}', '{"Real-time monitoring across 25M+ sources","AI sentiment analysis (positive / negative / neutral)","Automated PR coverage reports","Hashtag tracking + influencer identification","Multi-language support (108 languages)","Reputation scoring with trend lines and word clouds","Email + Slack alerts on mentions","Competitor comparison dashboards","Boolean search operators","Historical mention archive"}', '{"Slack","Email","Zapier","Make","Google Sheets","Microsoft Excel"}', true, '{"SMB and mid-market brands needing affordable PR + social monitoring","PR and comms teams tracking earned-media coverage at scale","Marketing teams measuring campaign reach across 100+ languages","Competitive intelligence ops monitoring competitor mentions"}', '{"Enterprise teams needing deep social-data licensing (Talkwalker / Meltwater fit)","Pure social-publishing workflows (use Hootsuite / Sprout Social)","Agencies needing white-label client dashboards (Brandwatch is stronger)","Influencer-marketing-only stacks (use CreatorIQ / Aspire / Grin)"}', 'The default SMB social-listening tool — Brand24 covers 25M+ sources with sentiment analysis at a price point Talkwalker and Meltwater can''t match without a six-figure contract. The 108-language support and real-time alerting are genuinely useful for global brand monitoring. It''s weaker than Talkwalker on enterprise data licensing, weaker than Sprinklr on suite-level marketing-cloud integration, and the no-public-tier-pricing posture from the homepage is friction. Pick Brand24 when you''re an SMB brand or PR team needing real coverage without enterprise budget; skip if you''re scaling past mid-market.', now()),

-- ── landbot → automation-agents ─────────────────────────────
('Landbot', 'landbot', 'No-code conversational AI builder — visual flows, WhatsApp + web chat, hybrid rules + GPT engine for lead qualification.', 'Landbot is a no-code conversational AI platform that combines a visual drag-and-drop flow builder with an AI agent engine blending rule-based logic and generative LLMs. The product deploys chatbots and AI agents across websites and WhatsApp for lead qualification, sales-funnel automation, customer support, and form-replacement workflows. Visual elements include buttons, forms, carousels, and date pickers inside conversations; AI Copilot assists during bot configuration; LLM integration covers OpenAI and Google Gemini for free-text intent handling. Used by 12,000+ companies including Allianz, BNP Paribas, and Generali. Landbot positions against Tidio (web-chat-first), Drift / Intercom (B2B SaaS suites), ManyChat (Instagram + Messenger DM specialist), Botpress (developer-first open-source), and Voiceflow (voice + chat agent design). The differentiator is the visual no-code builder paired with a hybrid rules-plus-LLM engine.', 'https://landbot.io', 'freemium', '[]'::jsonb, 'beginner', true, '{"web","api"}', '{"Visual drag-and-drop flow builder","WhatsApp Business automation","Website chat widgets","AI agent engine — rules + generative AI","AI Copilot for in-context bot configuration","Interactive elements (buttons, forms, carousels, date pickers)","Multi-channel deployment (web + WhatsApp)","No-code template library","Real-time conversation analytics","Webhook + REST API"}', '{"Zapier","HubSpot","n8n","Google Sheets","Airtable","Mailchimp","Slack","Stripe","OpenAI","Google Gemini"}', true, '{"Marketing teams replacing forms with conversational lead-qualification flows","WhatsApp Business operators automating customer conversations at scale","Companies needing a no-code chatbot with hybrid rules + LLM intelligence","Agencies building chatbots for SMB clients without engineering"}', '{"Enterprise SaaS B2B customer-success workflows (Drift / Intercom fit)","Instagram-DM-first creators (ManyChat is purpose-built)","Developer teams wanting open-source self-host (use Botpress)","Voice-first agent workflows (Voiceflow / Synthflow / Vapi)"}', 'The most accessible no-code conversational AI builder for marketing teams in 2026 — Landbot''s visual flow builder plus hybrid rules + GPT engine ships chatbots in hours, not weeks. The WhatsApp + web-chat dual-channel deployment is unusually clean. It''s weaker than Drift / Intercom on B2B SaaS depth, weaker than ManyChat on Instagram DM growth motions, and the homepage''s missing public pricing is friction. Pick Landbot when you''re a marketing team converting forms to conversation; skip if your customers live in Instagram DMs (ManyChat) or you need open-source control (Botpress).', now()),

-- ── demodesk → business-finance ─────────────────────────────
('Demodesk', 'demodesk', 'AI sales agents — auto-record meetings, transcribe, summarize, score calls, and update CRM with zero setup.', 'Demodesk is an AI-powered sales platform that records and transcribes meetings across Zoom, Google Meet, and Microsoft Teams; generates summaries; drafts follow-ups; updates CRM fields automatically; and provides real-time coaching feedback to sales reps. AI Crew automates deal management and pipeline updates; AI Assistant handles capture + transcription + CRM data entry; AI Coach scores calls against custom scorecards and flags deal risks; AI Analyst aggregates pipeline insights, GTM analysis, and product feedback; AI CRM Concierge syncs to Salesforce / HubSpot / Pipedrive with zero configuration; Mobile Capture records phone calls and offline meetings. Supports 98 languages. Demodesk positions against Gong (revenue intelligence incumbent), Chorus (similar coaching depth), Fireflies (transcription-first), and tl;dv (recorder + summary), pitching itself as "one platform" replacing 3-4 point solutions.', 'https://demodesk.com', 'freemium', '[]'::jsonb, 'intermediate', true, '{"web","mobile","api"}', '{"AI Crew — auto deal management + pipeline updates","AI Assistant — recording, transcription, summaries, follow-ups, CRM sync","AI Coach — call scoring with custom scorecards + deal risk","AI Analyst — pipeline insights, GTM analysis, product feedback","AI CRM Concierge — zero-setup CRM field sync","Mobile Capture — phone calls + offline meetings","98-language support","Real-time coaching feedback during calls"}', '{"Salesforce","HubSpot","Pipedrive","Microsoft Teams","Google Meet","Zoom","Google Calendar","Outlook","Aircall"}', true, '{"Mid-market sales teams consolidating Gong + Fireflies + tl;dv into one platform","Sales managers running structured call coaching at scale","Outbound SDR teams needing CRM auto-sync without manual logging","Multi-language sales orgs (98-language support)"}', '{"Enterprise revenue intelligence buyers needing Gong''s analytics depth","Transcription-only workflows where Fireflies / Otter are cheaper","Solo founders / sub-5-person sales teams (overkill for low call volume)","Teams not on Salesforce / HubSpot / Pipedrive — CRM Concierge is the killer feature"}', 'The consolidation play in the AI sales meeting category — Demodesk bundles recording, transcription, scoring, CRM sync, and coaching that mid-market teams typically buy as Gong + Fireflies + tl;dv stitched together. The zero-setup CRM Concierge is genuinely useful for HubSpot or Salesforce shops. It''s weaker than Gong on enterprise analytics depth, weaker than Otter on pure transcription pricing, and 98-language support is more breadth than most teams need. Pick Demodesk when you want one tool for the full meeting lifecycle; skip if Gong-grade revenue intelligence is the actual requirement.', now()),

-- ── filevine → research-education ───────────────────────────
('Filevine', 'filevine', 'AI-native legal operating platform — LOIS for Word, Depo CoPilot, MedChron, and matter management for law firms and govt.', 'Filevine is an AI-native legal operating platform combining case management, matter workflow automation, and AI-assisted document drafting through LOIS (Legal Operating Intelligence System). LOIS for Word brings context-aware legal drafting directly into Microsoft Word; Phase Validation automates process validation across case phases; Depo CoPilot supports deposition prep and analysis; Ask LOIS provides a legal Q&A assistant grounded in firm documents; MedChron generates and visualizes medical record chronologies for personal-injury and litigation cases. Built for enterprise and government legal workloads (named clients include FedEx, Skadden, and Utah County Public Defenders). Filevine positions against Clio (general practice management, smaller firms), MyCase + PracticePanther (mid-market case management), Smokeball (small firm-focused), Lawmatics (legal CRM + intake), and Harvey AI (BigLaw-grade legal LLM, no case management). The differentiator is AI grounded in the firm''s own data plus end-to-end matter workflow, not just AI on top of generic legal corpora.', 'https://www.filevine.com', 'contact', '[]'::jsonb, 'intermediate', true, '{"web","api"}', '{"LOIS for Word — AI legal drafting in Microsoft Word","Phase Validation — automated process validation across case phases","Depo CoPilot — AI-powered deposition prep and analysis","Ask LOIS — legal Q&A grounded in firm documents","MedChron — medical record chronology generation","End-to-end deposition management","Case + matter management with workflow automation","Intake-to-resolution automation","Document-grounded AI (firm''s own data)"}', '{"Microsoft 365","Microsoft Word","Outlook"}', true, '{"Mid-to-large law firms needing AI-native case management with LOIS drafting","Personal-injury and litigation practices using MedChron + Depo CoPilot","Government legal departments (Utah County Public Defenders pattern)","Enterprise legal ops standardising on AI grounded in firm documents"}', '{"Solo practitioners or sub-5-attorney firms (Clio / Smokeball cheaper)","Firms wanting a generic legal LLM not grounded in own data (Harvey AI fits)","Buyers needing public pricing transparency before sales call","Practices outside US legal market (Filevine is US-focused)"}', 'The AI-native enterprise legal operating platform — Filevine''s LOIS suite (drafting in Word, Depo CoPilot, MedChron, Ask LOIS) is genuinely deeper than the AI features Clio / MyCase have bolted on. Personal-injury firms and government legal ops are the obvious sweet spot. It''s weaker than Clio on small-firm pricing accessibility, weaker than Harvey AI on raw legal-research LLM quality, and the no-public-pricing enterprise sales motion is friction for buyers wanting fast comparison. Pick Filevine when you''re mid-to-large and want AI grounded in your matter data; skip for solo / small-firm practices where Clio is cheaper and good enough.', now())

ON CONFLICT (slug) DO NOTHING;

INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'productivity'        WHERE t.slug = 'trainual'  ON CONFLICT DO NOTHING;
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'marketing-seo'       WHERE t.slug = 'brand24'   ON CONFLICT DO NOTHING;
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'automation-agents'   WHERE t.slug = 'landbot'   ON CONFLICT DO NOTHING;
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'business-finance'    WHERE t.slug = 'demodesk'  ON CONFLICT DO NOTHING;
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'research-education'  WHERE t.slug = 'filevine'  ON CONFLICT DO NOTHING;
